#!/usr/bin/env python3
from pathlib import Path
import json, html
ROOT=Path(__file__).resolve().parents[1]
idx=json.loads((ROOT/'hands-on/skill/textbook-chapter-lab/course/chapter-index.json').read_text())

def start(ch):return '終章を開始' if ch['chapter_id']=='final' else f"第{int(ch['chapter_id'])}章を開始"
def num(ch):return 'final' if ch['chapter_id']=='final' else str(int(ch['chapter_id']))
rows=[]
for ch in idx['chapters']:
    key=ch['chapter_id'];s=start(ch)
    rows.append(f'''<article class="chapter-card" data-key="{key}"><div class="eyebrow">{html.escape(ch['label'])}</div><h2>{html.escape(ch['title'])}</h2><p>{html.escape(ch['outcome'])}</p><div class="pills"><span>{ch['estimated_minutes']}分</span><span>Risk {ch['risk_level']}</span><span>{len(ch['slide_pages'])} slides</span></div><p><strong>主成果物:</strong> <code>{html.escape(ch['artifacts'][0])}</code></p><div class="commands"><button data-copy="{html.escape(s)}">Cursor: {html.escape(s)}</button><button data-copy="/textbook-chapter-lab {num(ch)}">Claude Code</button><button data-copy="$textbook-chapter-lab {html.escape(s)}">Codex</button></div><a class="read" href="complete.html#hands-on-{key}">本文の起動欄へ →</a></article>''')
page=f'''<!doctype html><html lang="ja"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>章番号ハンズオン - Claude Code実践教科書</title><style>
:root{{--ink:#1f2633;--orange:#e85019;--line:#ead7bd;--paper:#fffaf2}}*{{box-sizing:border-box}}body{{margin:0;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans JP",sans-serif;background:linear-gradient(145deg,#fff4df,#f7fbff);color:var(--ink);line-height:1.75}}header{{background:#171f33;color:#fff;padding:16px 24px}}header a{{color:#fff;text-decoration:none;margin-right:18px}}main{{max-width:1220px;margin:auto;padding:54px 22px 80px}}.hero{{background:#fff;border:1px solid var(--line);border-radius:26px;padding:36px;box-shadow:0 20px 60px rgba(60,39,20,.1)}}h1{{font-size:clamp(2rem,4vw,3.7rem);line-height:1.15}}.quick{{display:flex;gap:9px;flex-wrap:wrap;margin-top:22px}}.quick input{{flex:1;min-width:190px;padding:12px;border:1px solid var(--line);border-radius:10px;font-size:1rem}}button,.btn{{border:0;border-radius:10px;background:var(--orange);color:#fff;padding:11px 14px;font-weight:800;cursor:pointer;text-decoration:none}}.grid{{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:17px;margin-top:30px}}.chapter-card{{background:#fff;border:1px solid var(--line);border-radius:18px;padding:22px;box-shadow:0 10px 30px rgba(60,39,20,.06)}}.chapter-card h2{{margin:.2em 0}}.eyebrow{{color:var(--orange);font-weight:900;letter-spacing:.1em}}.pills{{display:flex;gap:7px;flex-wrap:wrap}}.pills span{{background:var(--paper);border:1px solid var(--line);border-radius:999px;padding:4px 9px;font-size:.82rem}}.commands{{display:flex;gap:7px;flex-wrap:wrap;margin:15px 0}}.commands button{{font-size:.82rem}}.read{{font-weight:800;color:#285cc5}}.toast{{position:fixed;right:18px;bottom:18px;background:#172c28;color:#fff;padding:10px 15px;border-radius:10px;opacity:0;transition:.2s}}.toast.show{{opacity:1}}code{{background:#eef2f6;padding:.15em .35em;border-radius:5px}}@media(max-width:800px){{.grid{{grid-template-columns:1fr}}.hero{{padding:24px}}}}</style></head><body><header><a href="index.html">トップ</a><a href="complete.html">全章ブログ</a><strong>章番号ハンズオン</strong></header><main><section class="hero"><div class="eyebrow">Cursor · Claude Code · Codex</div><h1>章番号を伝えて、すぐ実習を始める</h1><p>全40章が共通Skillに対応しています。ブログの章を読んだら、同じ章番号をAgentへ伝えてください。進捗は <code>.trepro-learning/</code> へ保存され、別Runtimeへ切り替えても再開できます。</p><div class="quick"><input id="q" placeholder="例: 12 / 第12章 / 終章"><button id="copy">開始文をコピー</button><button id="jump">章カードへ移動</button></div><p><strong>導入:</strong> パッケージ自体を開けば3Runtime用Skillが同梱済みです。別Projectでは <code>./hands-on/install.sh --runtime all --scope project --target /path/to/project</code> を実行します。</p></section><section class="grid">{''.join(rows)}</section></main><div class="toast">コピーしました</div><script>
const toast=document.querySelector('.toast');const cp=async t=>{{try{{await navigator.clipboard.writeText(t);toast.classList.add('show');setTimeout(()=>toast.classList.remove('show'),1100)}}catch{{prompt('コピーしてください',t)}}}};const norm=()=>{{let v=document.getElementById('q').value.trim();if(/^(終章|final|最後)$/i.test(v))return ['final','終章を開始'];v=v.replace(/chapter|chap|ch|チャプター|第|章|を開始|[-_ ]/gi,'');const n=Number(v);return Number.isInteger(n)&&n>=0&&n<=38?[String(n).padStart(2,'0'),`第${{n}}章を開始`]:null}};document.getElementById('copy').onclick=()=>{{const r=norm();if(!r)return alert('0〜38、または終章を入力してください');cp(r[1])}};document.getElementById('jump').onclick=()=>{{const r=norm();if(!r)return alert('0〜38、または終章を入力してください');document.querySelector(`[data-key="${{r[0]}}"]`).scrollIntoView({{behavior:'smooth'}})}};document.querySelectorAll('[data-copy]').forEach(b=>b.onclick=()=>cp(b.dataset.copy));</script></body></html>'''
(ROOT/'site'/'hands-on.html').write_text(page,encoding='utf-8')

index_site='''<!doctype html><html lang="ja"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Claude Code実践教科書 - 体験統合版</title><style>body{margin:0;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans JP",sans-serif;background:linear-gradient(145deg,#fff3dc,#f5f9ff);color:#231b16;line-height:1.8}.wrap{max-width:1080px;margin:auto;padding:64px 22px}.hero{background:#fff;border:1px solid #f0d3b0;border-radius:28px;padding:48px;box-shadow:0 24px 70px rgba(91,50,17,.13)}.eyebrow{color:#e64a16;font-weight:900;letter-spacing:.12em;text-transform:uppercase}h1{font-size:clamp(2.2rem,5vw,4.2rem);line-height:1.16;margin:.25em 0}.actions{display:flex;gap:12px;flex-wrap:wrap;margin:28px 0}.btn{padding:12px 20px;border-radius:999px;text-decoration:none;border:1px solid #e64a16;color:#e64a16;font-weight:800}.primary{background:#e64a16;color:white}.grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.card{padding:18px;border:1px solid #f0dfcb;border-radius:16px;background:#fffaf3}.card strong{display:block;font-size:1.35rem;color:#e64a16}@media(max-width:800px){.hero{padding:27px}.grid{grid-template-columns:1fr 1fr}}@media(max-width:520px){.grid{grid-template-columns:1fr}}</style></head><body><main class="wrap"><section class="hero"><div class="eyebrow">Experiential Edition v2.0</div><h1>Claude Code実践教科書<br>スライド×ブログ×章番号ハンズオン</h1><p>スライドPDF全147ページを、該当する文章と小見出しの間へ一枚ずつ配置。全40章には完全初心者向け補助線と、Cursor・Claude Code・Codexで即時起動できる共通Skillを組み込みました。</p><div class="actions"><a class="btn primary" href="complete.html">統合ブログを読む</a><a class="btn" href="hands-on.html">章番号から実習</a><a class="btn" href="../SLIDE_PLACEMENT_MAP.md">配置表</a></div><div class="grid"><div class="card"><strong>147 / 147</strong>PDF全ページ</div><div class="card"><strong>40 / 40</strong>章別Lab</div><div class="card"><strong>160 Steps</strong>証拠ベース</div><div class="card"><strong>Save / Resume</strong>Runtime共通</div></div></section></main></body></html>'''
(ROOT/'site'/'index.html').write_text(index_site,encoding='utf-8')
(ROOT/'index.html').write_text(index_site.replace('href="complete.html"','href="site/complete.html"').replace('href="hands-on.html"','href="site/hands-on.html"').replace('href="../SLIDE_PLACEMENT_MAP.md"','href="SLIDE_PLACEMENT_MAP.md"'),encoding='utf-8')
print('written')
